mapper.select:
SELECT TO_CHAR(o.offering_date, 'YYYY-MM') AS month, COALESCE(SUM(CASE WHEN o.offering_type = 'TITHE' THEN o.amount ELSE 0 END), 0) AS tithe, COALESCE(SUM(CASE WHEN o.offering_type = 'MISSION' THEN o.amount ELSE 0 END), 0) AS mission, COALESCE(SUM(CASE WHEN o.offering_type = 'SPECIAL' THEN o.amount ELSE 0 END), 0) AS special, COALESCE(SUM(CASE WHEN o.offering_type NOT IN ('TITHE', 'MISSION', 'SPECIAL') THEN o.amount ELSE 0 END), 0) AS other, COALESCE(SUM(o.amount), 0) AS total FROM erp_offering o
TO_CHAR(o.offering_date, 'YYYY') = #{year}
AND TO_CHAR(o.offering_date, 'MM') = #{month}
GROUP BY TO_CHAR(o.offering_date, 'YYYY-MM') ORDER BY TO_CHAR(o.offering_date, 'YYYY-MM') DESC
